content:
{
  "flashcards": [
    {
      "front": "Bonjour",
      "back": {
        "translation": "Hallo",
        "pronunciation": "[bɔ̃.ʒuʁ]",
        "example": "Bonjour, comment allez-vous?",
        "exampleTranslation": "Hallo, wie geht es Ihnen?"
      },
      "mnemonic": "Bonn - der Kuchen, aber 'Bonjour' ist eine Begrüßung im Französischen.",
      "imagePrompt": "A smiling man waving hello with the word 'Bonjour' written in a bright yellow speech bubble"
    },
    {
      "front": "Salut",
      "back": {
        "translation": "Hallo",
        "pronunciation": "[saly]",
        "example": "Salut, Marie! Comment ça va?",
        "exampleTranslation": "Hallo, Marie! Wie geht es dir?"
      },
      "mnemonic": "Salut klingt wie 'Sau-Lut', aber denk an Salut als schnelle Begrüßung.",
      "imagePrompt": "A friendly teenager waving one hand with the word 'Salut' in a casual green sticker"
    },
    {
      "front": "Au revoir",
      "back": {
        "translation": "Auf Wiedersehen",
        "pronunciation": "[o.ʁə.vwaʁ]",
        "example": "Au revoir, à demain!",
        "exampleTranslation": "Auf Wiedersehen, bis morgen!"
      },
      "mnemonic": "A-u-re-v-o-i-r – 'auch wieder' = bis bald.",
      "imagePrompt": "A person walking away with a hand raised and the word 'Au revoir' in a blue banner above"
    },
    {
      "front": "Merci",
      "back": {
        "translation": "Danke",
        "pronunciation": "[mɛʁ.si]",
        "example": "Merci beaucoup!",
        "exampleTranslation": "Vielen Dank!"
      },
      "mnemonic": "Mer-ki – wie 'Merk dir' = merken, dass man dankt.",
      "imagePrompt": "A hand giving a small gift with the word 'Merci' in a pink heart-shaped card"
    },
    {
      "front": "S'il vous plaît",
      "back": {
        "translation": "Bitte",
        "pronunciation": "[sil.vu.plɛ]",
        "example": "Un verre d'eau, s'il vous plaît.",
        "exampleTranslation": "Ein Glas Wasser, bitte."
      },
      "mnemonic": "S'il vous plaît – 'sicherlich' oder wie 'Bitte', aber formell.",
      "imagePrompt": "A person holding out a glass with the word 'S'il vous plaît' on a small white card"
    },
    {
      "front": "Bonjour!",
      "back": {
        "translation": "Guten Tag!",
        "pronunciation": "[bɔ̃.ʒuʁ]",
        "example": "Bonjour! Je m'appelle Paul.",
        "exampleTranslation": "Guten Tag! Ich heiße Paul."
      },
      "mnemonic": "Bon – gut, jour – Tag → Guter Tag = Bonjour!",
      "imagePrompt": "A man in a suit saying 'Bonjour!' with the sun shining above"
    },
    {
      "front": "Bonsoir",
      "back": {
        "translation": "Guten Abend",
        "pronunciation": "[bɔ̃.swaʁ]",
        "example": "Bonsoir, c'est l'heure du dîner.",
        "exampleTranslation": "Guten Abend, es ist Zeit zum Essen."
      },
      "mnemonic": "Bons – gut, soir – Abend → Guter Abend = Bonsoir!",
      "imagePrompt": "A cozy evening scene with a family at dinner table and the word 'Bonsoir' glowing softly"
    },
    {
      "front": "Oui",
      "back": {
        "translation": "Ja",
        "pronunciation": "[wɛ]",
        "example": "Tu as un livre? Oui, j'ai un livre.",
        "exampleTranslation": "Hast du ein Buch? Ja, ich habe ein Buch."
      },
      "mnemonic": "Oui – klingt wie 'U' und ist die Antwort auf 'ja'.",
      "imagePrompt": "A big green checkmark with the word 'Oui' written in white letters"
    },
    {
      "front": "Non",
      "back": {
        "translation": "Nein",
        "pronunciation": "[nɔ̃]",
        "example": "Tu es français? Non, je suis allemand.",
        "exampleTranslation": "Bist du Franzose? Nein, ich bin Deutscher."
      },
      "mnemonic": "Non – wie 'N' und 'on', also nicht = Nein.",
      "imagePrompt": "A red cross with the word 'Non' written in bold white letters"
    },
    {
      "front": "Comment ça va?",
      "back": {
        "translation": "Wie geht es dir?",
        "pronunciation": "[kɔ.mɑ̃.sa.vɑ]",
        "example": "Comment ça va? Je vais bien.",
        "exampleTranslation": "Wie geht es dir? Mir geht es gut."
      },
      "mnemonic": "Komment – klingt wie 'kommt', und 'ça va' = geht es, also: Wie geht es dir?",
      "imagePrompt": "A smiling person with a thought bubble showing the phrase 'Comment ça va?'"
    }
  ]
}
